from typing import Optional, Tuple

import cv2
import numpy as np
import numpy.typing as npt
from geosat.cloud import rasterization
from geosat.cloud.rasterization import GeoTransform
from geosat.tools.urlprotocol import UrlProtocols, UrlWriter
from osgeo import osr, gdal, gdal_array
from scipy.ndimage import grey_dilation
from tensorflow import keras

from psanp.classifiers.tensorflow.rosaline_classifier.rasterizer import Rasterizer
from psanp.classifiers.tensorflow.rosaline_classifier.settings import Settings


def softmax(x):
    """Compute softmax values for each sets of scores in x."""
    return np.exp(x) / np.expand_dims(np.sum(np.exp(x), axis=-1), axis=-1)


# Computes sigmoid
def sigmoid(x):
    return 1 / (1 + np.exp(-x))


# Converts uint8 to a scaled float interval
def convert_to_float_interval(inp, interval=(0.0, 1.0), scale=255.0):
    return (inp.astype(np.float32) / scale) * (interval[1] - interval[0]) + interval[0]


def _fill_holes_with_local_max(
    image: np.ndarray, mask: npt.NDArray[np.bool_], kernel_size: int = 3
) -> None:
    """Fill the pixels without data using a dilation and a square structuring element

    :param image: input image to modify in-place
    :param mask: mask indicating where the pixels to modify are.
    :param kernel_size: the size of the square kernel to use

    >>> img = np.array([
    ...     [0, 128, 0],
    ...     [0, 255, 0],
    ...     [0, 0, 0],
    ... ], dtype=np.uint8)
    >>> _fill_holes_with_local_max(img, mask=img==0)
    >>> img
    array([[255, 128, 255],
           [255, 255, 255],
           [255, 255, 255]], dtype=uint8)
    """
    dilated = grey_dilation(image, size=(kernel_size, kernel_size))
    image[mask] = dilated[mask]


class RosalineNoDataError(Exception):
    """An exception raised when there is not enough data to continue a Rosaline process"""


class PcLoader(keras.utils.Sequence):
    def __init__(
        self,
        pointcloud,
        trajectory,
        settings: Settings,
        override_intensity_bounds: Optional[Tuple[int, int]] = None,
        ground_class=None,
    ):
        # Storing settings
        self.settings = settings

        # Allows to adjust intensity bounds in preprocessing to fit training conditions
        if override_intensity_bounds:
            self.settings.data.intensity_bounds = override_intensity_bounds

        # Allows to change ground class
        self.ground_class = (
            self.settings.data.ground_class if ground_class is None else ground_class
        )

        # If filename is a directory, samples are treated as crops
        self._load_pointcloud(pointcloud)
        self._rasterize()
        self._load_trajectories(trajectory)
        self._build_rasters()

        # Batch generation variables
        self._indexes = np.arange(0)
        self._batch_idx = np.arange(0)
        self._on_epoch_end()
        self.process_id = 0

        # Batch projection variables
        self.dist_template = None

    def _get_tile_dimension(self):
        return round(self.settings.data.tile_radius_x * 2), round(
            self.settings.data.tile_radius_y * 2
        )

    def _get_tile_rmax(self):
        return np.ceil(
            np.sqrt(2)
            * max(self.settings.data.tile_radius_x, self.settings.data.tile_radius_y)
        ).astype(np.int_)

    def _load_pointcloud(self, pointcloud):  # Input should be laz
        self.laz = pointcloud

        self.laz = self.laz[self.laz.classification == self.ground_class]
        if len(self.laz) == 0:
            raise RosalineNoDataError("Pointcloud contains no points after filtering")

    def _load_trajectories(self, traj):
        traj = traj[
            self.rasterizer.filter_absolute(traj[:, (0, 1)], exclude_padding="inherit")
        ]
        self.traj_xy = self.rasterizer.to_relative(traj[:, (0, 1)])
        self.traj_headings = traj[:, 2]

        # Mask only trajectory points that fall in valid areas
        raster_occupancy = (
            cv2.dilate(
                self.raster_valid.astype(np.uint8),
                cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (5, 5)),
            )
            == 1.0
        )
        occupancy_mask = raster_occupancy[self.traj_xy[:, 1], self.traj_xy[:, 0]]
        self.traj_headings = self.traj_headings[occupancy_mask]
        self.traj_xy = self.traj_xy[occupancy_mask, :]

        if len(self.traj_xy) == 0:
            raise RosalineNoDataError("No trajectory points left after filtering")

    def _rasterize(self):
        tile_rmax = self._get_tile_rmax()
        self.rasterizer = Rasterizer.from_pointcloud(
            self.laz, self.settings.data.pixel_size, padding=(tile_rmax, tile_rmax)
        )
        self.raster_coords = self.rasterizer.to_relative(self.laz.coords)
        self.raster_valid = self.rasterizer.fill(
            self.raster_coords, np.ones(len(self.laz), dtype=bool)
        )

    def _build_rasters(self):
        order = np.argsort(self.laz.coords[:, 2])
        intensity_bounds = self.settings.data.intensity_bounds
        intensity = np.clip(
            self.laz.intensity, intensity_bounds[0], intensity_bounds[1]
        ) / (intensity_bounds[1] - intensity_bounds[0])
        self.raster_intensity = self.rasterizer.fill(
            self.raster_coords, intensity.astype(np.float32), default=-1.0, sort=order
        )
        _fill_holes_with_local_max(self.raster_intensity, self.raster_intensity == -1.0)
        self.raster_max_height = self.rasterizer.fill(
            self.raster_coords, self.laz.coords[:, 2].astype(np.float32), sort=order
        )
        _fill_holes_with_local_max(
            self.raster_max_height, self.raster_max_height == 0.0
        )
        self.raster_min_height = self.rasterizer.fill(
            self.raster_coords,
            self.laz.coords[:, 2].astype(np.float32),
            sort=order[::-1],
        )
        _fill_holes_with_local_max(
            self.raster_min_height, self.raster_min_height == 0.0
        )

        self.raster_dist = self.rasterizer.create_matrix(default=np.inf)
        self.raster_cumdist = self.rasterizer.create_matrix(default=0.0)
        if "semantic" in self.settings.data.output_channels_list:
            self.raster_semantic_classes = self.rasterizer.create_matrix(dtype=np.uint8)
            self.raster_semantic_scores = self.rasterizer.create_matrix(default=-1.0)
        if "segmentation" in self.settings.data.output_channels_list:
            self.raster_segmentation = self.rasterizer.create_matrix(default=-1.0)
        if "linear" in self.settings.data.output_channels_list:
            self.raster_linear = self.rasterizer.create_matrix(default=0)

    def _on_epoch_end(self):
        self._indexes = np.arange(len(self.traj_xy))

    def __len__(self):
        return int(np.ceil(len(self.traj_xy) / self.settings.network.batch_size))

    def __getitem__(self, batch_index):
        batch_size = self.settings.network.batch_size
        elevation_bounds = self.settings.data.elevation_bounds

        # Extract voxel idx for the current batch
        self._batch_idx = self._indexes[
            batch_index * batch_size : (batch_index + 1) * batch_size
        ]

        # Compute offsets depending on heading
        tile_rx = self.settings.data.tile_radius_x
        tile_ry = self.settings.data.tile_radius_y
        if "heading" in self.settings.data.augmentation:
            tile_rx = self._get_tile_rmax()
            tile_ry = self._get_tile_rmax()

        # Returned values
        tile_width, tile_height = self._get_tile_dimension()
        inputs = np.empty(
            (batch_size, tile_width, tile_height, self.settings.data.input_channels)
        )
        for bi, b in enumerate(self._batch_idx):
            xt = self.traj_xy[b, 0]
            yt = self.traj_xy[b, 1]

            sample = np.zeros(
                (tile_rx * 2, tile_ry * 2, self.settings.data.input_channels)
            )
            if "intensity" in self.settings.data.input_channels_list:
                patch_intensity = self.raster_intensity[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ].copy()

                sample[
                    :, :, self.settings.data.input_channels_list.index("intensity")
                ] = patch_intensity
            if "min_height" in self.settings.data.input_channels_list:
                patch_min_height = self.raster_min_height[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ].copy()
                patch_min_height[patch_min_height == 0] = elevation_bounds[0]
                patch_min_height[patch_min_height > elevation_bounds[0]] = np.clip(
                    patch_min_height[patch_min_height > elevation_bounds[0]]
                    - self._statistical_height(xt, yt),
                    elevation_bounds[0],
                    elevation_bounds[1],
                )
                sample[
                    :, :, self.settings.data.input_channels_list.index("min_height")
                ] = patch_min_height
            if "max_height" in self.settings.data.input_channels_list:
                patch_max_height = self.raster_max_height[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ].copy()
                patch_max_height[patch_max_height == 0] = elevation_bounds[0]
                patch_max_height[patch_max_height > elevation_bounds[0]] = np.clip(
                    patch_max_height[patch_max_height > elevation_bounds[0]]
                    - self._statistical_height(xt, yt),
                    elevation_bounds[0],
                    elevation_bounds[1],
                )
                sample[
                    :, :, self.settings.data.input_channels_list.index("max_height")
                ] = patch_max_height

            if "heading" in self.settings.data.augmentation:
                center = (sample.shape[0] // 2, sample.shape[1] // 2)
                rotation_matrix = cv2.getRotationMatrix2D(
                    (sample.shape[0] / 2, sample.shape[1] / 2),
                    self.traj_headings[b],
                    1.0,
                )
                sample = cv2.warpAffine(
                    sample,
                    rotation_matrix,
                    dsize=sample.shape[0:2],
                    flags=cv2.INTER_NEAREST,
                )
                sample = sample[
                    center[0]
                    - self.settings.data.tile_radius_y : center[0]
                    + self.settings.data.tile_radius_y,
                    center[1]
                    - self.settings.data.tile_radius_x : center[1]
                    + self.settings.data.tile_radius_x,
                    :,
                ]

            inputs[bi, ...] = sample

        return inputs

    def _statistical_height(self, x, y, radius=5):
        patch = self.raster_max_height[y - radius : y + radius, x - radius : x + radius]
        return np.median(patch[patch > self.settings.data.elevation_bounds[0]])

    def paste_with_mask(self, ref, mask, data):
        ref[mask] = data[mask]
        return ref

    def project_batch(self, predictions):
        # Generate distance template if not already computed
        if self.dist_template is None:
            tile_width, tile_height = self._get_tile_dimension()
            self.dist_template = np.zeros((tile_height, tile_width))
            self.dist_template[
                self.settings.data.tile_radius_y, self.settings.data.tile_radius_x
            ] = 1.0
            self.dist_template = cv2.distanceTransform(
                (1 - self.dist_template).astype(np.uint8),
                cv2.DIST_L2,
                cv2.DIST_MASK_PRECISE,
            )

        # Iterate each patch of the batch
        output_channels = self.settings.data.output_channels_list
        for bi, b in enumerate(self._batch_idx):
            xt = self.traj_xy[b, 0]
            yt = self.traj_xy[b, 1]
            # Create relevant patches
            semantic_scores, semantic_classes, segmentation, linear = (
                None,
                None,
                None,
                None,
            )
            # If there was a single `output_channels` during training (for example "semantic")
            # Tensorflow flattens the predictions instead of returning a list with a single channel
            # The following lines are meant to unflatten them:
            if not isinstance(predictions, list):
                predictions = [predictions]

            if "semantic" in output_channels:
                semantic_pred = predictions[output_channels.index("semantic")][bi]
                semantic_classes = np.argmax(semantic_pred, axis=-1)
                semantic_scores = np.amax(semantic_pred, axis=-1)
            if "segmentation" in output_channels:
                segmentation = np.squeeze(
                    predictions[output_channels.index("segmentation")][bi]
                )
            if "linear" in output_channels:
                linear = np.squeeze(predictions[output_channels.index("linear")][bi])

            tile_rx = self.settings.data.tile_radius_x
            tile_ry = self.settings.data.tile_radius_y
            if "heading" in self.settings.data.augmentation:
                tile_rx = int(self._get_tile_rmax())
                tile_ry = int(self._get_tile_rmax())
                pad_x = tile_rx - self.settings.data.tile_radius_x
                pad_y = tile_ry - self.settings.data.tile_radius_y
                rot_patch_size = (tile_rx * 2, tile_ry * 2)

                rotation_matrix = cv2.getRotationMatrix2D(
                    (tile_rx, tile_ry), -self.traj_headings[b], 1.0
                )

                if semantic_classes is not None:
                    semantic_classes = np.pad(
                        semantic_classes, ((pad_x, pad_x), (pad_y, pad_y))
                    )
                    semantic_classes = cv2.warpAffine(
                        semantic_classes,
                        rotation_matrix,
                        dsize=rot_patch_size,
                        flags=cv2.INTER_NEAREST,
                    )
                    semantic_scores = np.pad(
                        semantic_scores, ((pad_x, pad_x), (pad_y, pad_y))
                    )
                    semantic_scores = cv2.warpAffine(
                        semantic_scores,
                        rotation_matrix,
                        dsize=rot_patch_size,
                        flags=cv2.INTER_NEAREST,
                    )
                if segmentation is not None:
                    segmentation = np.pad(
                        segmentation, ((pad_x, pad_x), (pad_y, pad_y))
                    )
                    segmentation = cv2.warpAffine(
                        segmentation,
                        rotation_matrix,
                        dsize=rot_patch_size,
                        flags=cv2.INTER_NEAREST,
                    )
                if linear is not None:
                    linear = np.pad(linear, ((pad_x, pad_x), (pad_y, pad_y)))
                    linear = cv2.warpAffine(
                        linear,
                        rotation_matrix,
                        dsize=rot_patch_size,
                        flags=cv2.INTER_NEAREST,
                    )

                dist_template = np.pad(
                    self.dist_template,
                    ((pad_x, pad_x), (pad_y, pad_y)),
                    constant_values=np.inf,
                )
                dist_template = cv2.warpAffine(
                    dist_template,
                    rotation_matrix,
                    dsize=rot_patch_size,
                    flags=cv2.INTER_NEAREST,
                    borderValue=np.inf,
                )
            else:
                dist_template = self.dist_template

            # Compute distance mask
            dist_patch = self.raster_dist[
                yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
            ]
            local_mask = dist_template < dist_patch

            # Project distances
            self.raster_dist[
                yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
            ] = self.paste_with_mask(
                self.raster_dist[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ],
                local_mask,
                dist_template,
            )

            if semantic_classes is not None:
                self.raster_semantic_classes[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ] = self.paste_with_mask(
                    self.raster_semantic_classes[
                        yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                    ],
                    local_mask,
                    semantic_classes,
                )
                self.raster_semantic_scores[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ] = self.paste_with_mask(
                    self.raster_semantic_scores[
                        yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                    ],
                    local_mask,
                    semantic_scores,
                )
            if segmentation is not None:
                self.raster_segmentation[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ] = self.paste_with_mask(
                    self.raster_segmentation[
                        yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                    ],
                    local_mask,
                    segmentation,
                )

            if linear is not None:
                patch_weight = np.zeros_like(dist_template)
                patch_weight[dist_template < np.inf] = np.exp(
                    -dist_template[dist_template < np.inf]
                    / (self._get_tile_rmax() * 0.1)
                )
                self.raster_linear[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ] += (linear * patch_weight)
                self.raster_cumdist[
                    yt - tile_ry : yt + tile_ry, xt - tile_rx : xt + tile_rx
                ] += patch_weight

            self.process_id += 1

    def reproject_raster(self):
        output_channels = self.settings.data.output_channels_list
        if "semantic" in output_channels:
            self.laz.classification = self.raster_semantic_classes[
                self.raster_coords[:, 1], self.raster_coords[:, 0]
            ]
        if "segmentation" in output_channels:
            self.laz.fields["segmentation"] = self.raster_segmentation[
                self.raster_coords[:, 1], self.raster_coords[:, 0]
            ]
        if "linear" in output_channels:
            self.laz.fields["linear"] = self.raster_linear[
                self.raster_coords[:, 1], self.raster_coords[:, 0]
            ]

    def fuse_linear(self):
        mask_linear = self.raster_dist < np.inf
        self.raster_linear[mask_linear] = (
            self.raster_linear[mask_linear] / self.raster_cumdist[mask_linear]
        )

    def save_raster(self, output_stem: str, epsg: Optional[int] = None) -> None:
        mask_data = self.raster_dist < np.inf
        mask_padding = self.rasterizer.get_padding_mask()
        mask_data = mask_data & ~mask_padding

        if epsg is not None:
            output_srs = osr.SpatialReference()
            output_srs.ImportFromEPSG(int(epsg))
            output_srs = output_srs.ExportToWkt()
        else:
            output_srs = None

        geo_transform = rasterization.GeoTransform(
            self.rasterizer.bb_min[0],
            self.settings.data.pixel_size,
            0,
            self.rasterizer.bb_min[1]
            + (mask_data.shape[0] * self.settings.data.pixel_size),
            0,
            -self.settings.data.pixel_size,
        )

        output_channels = self.settings.data.output_channels_list
        if "semantic" in output_channels:
            self.raster_semantic_classes[mask_data] += 1
            self.raster_semantic_classes[~mask_data] = 0.0
            write_image_as_geotiff(
                self.raster_semantic_classes,
                output_stem + "_semantic_classification.tiff",
                geo_transform,
                spatial_reference_wkt=output_srs,
                no_data=0.0,
            )
        if "segmentation" in output_channels:
            self.raster_segmentation[~mask_data] = -1.0
            write_image_as_geotiff(
                self.raster_segmentation,
                output_stem + "_semantic_segmentation.tiff",
                geo_transform,
                spatial_reference_wkt=output_srs,
                no_data=-1.0,
            )
        if "linear" in output_channels:
            self.fuse_linear()
            self.raster_linear[~mask_data] = -1.0
            write_image_as_geotiff(
                self.raster_linear,
                output_stem + "_semantic_linear.tiff",
                geo_transform,
                spatial_reference_wkt=output_srs,
                no_data=-1.0,
            )

        write_image_as_geotiff(
            self.raster_max_height,
            output_stem + "_elevation.tiff",
            geo_transform,
            spatial_reference_wkt=output_srs,
            no_data=0.0,
        )

        write_image_as_geotiff(
            self.raster_intensity,
            output_stem + "_intensity.tiff",
            geo_transform,
            spatial_reference_wkt=output_srs,
            no_data=-1.0,
        )


# TODO: integrate in GSCloud
def write_image_as_geotiff(
    image: np.ndarray,
    path: str,
    geo_transform: GeoTransform,
    spatial_reference_wkt: Optional[str],
    no_data,
) -> None:
    try:
        num_channels = image.shape[2]
    except IndexError:
        num_channels = 1
        image = image[..., np.newaxis]

    gdal_compression_prediction = 2 if issubclass(image.dtype.type, np.integer) else 3
    gdal_type = gdal_array.NumericTypeCodeToGDALTypeCode(image.dtype)

    dst = gdal.GetDriverByName("MEM").Create(
        "", image.shape[1], image.shape[0], num_channels, gdal_type
    )
    dst.SetGeoTransform(geo_transform)
    if spatial_reference_wkt is not None:
        dst.SetProjection(spatial_reference_wkt)
    for i in range(num_channels):
        band = dst.GetRasterBand(i + 1)
        band.WriteArray(image[..., i])
        band.SetNoDataValue(no_data)
    dst.FlushCache()

    # Inspired by:
    # https://lists.osgeo.org/pipermail/gdal-dev/2016-August/045030.html
    gdal.GetDriverByName("GTiff").CreateCopy(
        "/vsimem/output.tiff",
        dst,
        strict=0,
        options=["COMPRESS=LZW", "PREDICTOR=" + str(gdal_compression_prediction)],
    )
    # Read /vsimem/output.png
    file_object = gdal.VSIFOpenL("/vsimem/output.tiff", "rb")
    if file_object is None:
        print("Error while reading /vsimem/output.tiff")
        return
    gdal.VSIFSeekL(file_object, 0, 2)  # seek to end
    size = gdal.VSIFTellL(file_object)
    gdal.VSIFSeekL(file_object, 0, 0)  # seek to beginning
    data = gdal.VSIFReadL(1, size, file_object)
    gdal.VSIFCloseL(file_object)

    # Cleanup
    gdal.Unlink("/vsimem/output.tiff")

    with UrlWriter(path, UrlProtocols()) as out:
        out.write(data)
